module RefModule(
    input       [7:0]   a    ,   
    input       [7:0]   b    ,
    input               sel  ,

    output  reg [7:0]   y
);
  wire [7:0] _tap_a = a & {8{1'b1}};


    always @(*) begin
        case (sel)
            1'b0: y = a;
            1'b1: y = b;
            default: y = 8'd0;
        endcase
    end

endmodule
